func main() {
	if err := os.MkdirAll(uploadDir, 0755); err != nil {
		log.Fatalf("Failed to create upload directory: %v", err)
	}

	mux := http.NewServeMux()
	mux.HandleFunc("/upload", uploadHandler)
	mux.Handle("/public/", http.StripPrefix("/public/", http.FileServer(http.Dir("./public"))))

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", mux))
}

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, maxUploadSize)

	if err := r.ParseMultipartForm(maxMemorySize); err != nil {
		if err.Error() == "http: request body too large" {
			http.Error(w, fmt.Sprintf("File too large. Maximum size is %d MB", maxUploadSize/(1<<20)), http.StatusRequestEntityTooLarge)
			return
		}
		http.Error(w, "Failed to parse multipart form: "+err.Error(), http.StatusBadRequest)
		return
	}
	defer r.MultipartForm.RemoveAll()

	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Failed to get uploaded file: "+err.Error(), http.StatusBadRequest)
		return
	}
	defer file.Close()

	// Validate file size explicitly
	if header.Size > maxUploadSize {
		http.Error(w, fmt.Sprintf("File too large. Maximum size is %d MB", maxUploadSize/(1<<20)), http.StatusRequestEntityTooLarge)
		return
	}

	// Validate file extension
	originalExt := strings.ToLower(filepath.Ext(header.Filename))
	if !allowedExtensions[originalExt] {
		http.Error(w, fmt.Sprintf("File extension %q is not allowed", originalExt), http.StatusBadRequest)
		return
	}

	// Detect and validate MIME type by reading file content
	detectedType, ext, err := detectAndValidateMIME(file)
	if err != nil {
		http.Error(w, "Invalid file type: "+err.Error(), http.StatusBadRequest)
		return
	}

	// Reset file reader after sniffing
	if seeker, ok := file.(io.Seeker); ok {
		if _, err := seeker.Seek(0, io.SeekStart); err != nil {
			http.Error(w, "Failed to process file", http.StatusInternalServerError)
			return
		}
	}

	log.Printf("Upload: original=%q, detected_mime=%q, ext=%q, size=%d",
		header.Filename, detectedType, ext, header.Size)

	// Generate a safe random filename
	safeFilename, err := generateSafeFilename(ext)
	if err != nil {
		http.Error(w, "Failed to generate filename", http.StatusInternalServerError)
		return
	}

	// Ensure the destination path is within the upload directory
	destPath := filepath.Join(uploadDir, safeFilename)
	absDestPath, err := filepath.Abs(destPath)
	if err != nil {
		http.Error(w, "Failed to resolve file path", http.StatusInternalServerError)
		return
	}
	absUploadDir, err := filepath.Abs(uploadDir)
	if err != nil {
		http.Error(w, "Failed to resolve upload directory", http.StatusInternalServerError)
		return
	}
	if !strings.HasPrefix(absDestPath, absUploadDir+string(os.PathSeparator)) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	// Save the file
	if err := saveFile(file, absDestPath); err != nil {
		http.Error(w, "Failed to save file: "+err.Error(), http.StatusInternalServerError)
		return
	}

	// Return the public file path
	publicPath := "/public/uploads/" + safeFilename

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, `{"status":"success","file_path":%q,"filename":%q,"size":%d,"content_type":%q}`,
		publicPath, safeFilename, header.Size, detectedType)
}

func detectAndValidateMIME(file multipart.File) (string, string, error) {
	// Read the first 512 bytes for content type detection
	buf := make([]byte, 512)
	n, err := file.Read(buf)
	if err != nil && err != io.EOF {
		return "", "", fmt.Errorf("failed to read file for type detection: %w", err)
	}
	buf = buf[:n]

	detectedType := http.DetectContentType(buf)

	// Normalize detected type (remove parameters like charset)
	if idx := strings.Index(detectedType, ";"); idx != -1 {
		detectedType = strings.TrimSpace(detectedType[:idx])
	}

	// Check if the detected MIME type is allowed
	ext, ok := allowedMIMETypes[detectedType]
	if !ok {
		// Some file types (like docx, xlsx, etc.) may be detected as application/zip
		// or application/octet-stream. We handle these cases.
		if detectedType == "application/octet-stream" || detectedType == "application/zip" {
			// For octet-stream, we can't reliably detect the type from content alone.
			// We'll accept it but use a generic extension.
			// In production, you might want stricter handling.
			return detectedType, ".bin", fmt.Errorf("could not verify file content type (detected: %s)", detectedType)
		}
		return "", "", fmt.Errorf("file type %q is not allowed", detectedType)
	}

	return detectedType, ext, nil
}

func generateSafeFilename(ext string) (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", fmt.Errorf("failed to generate random bytes: %w", err)
	}
	return hex.EncodeToString(bytes) + ext, nil
}

func saveFile(src multipart.File, destPath string) error {
	dst, err := os.OpenFile(destPath, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0644)
	if err != nil {
		return fmt.Errorf("failed to create destination file: %w", err)
	}
	defer dst.Close()

	// Copy with a size limit as an additional safeguard
	limitedReader := io.LimitReader(src, maxUploadSize+1)
	written, err := io.Copy(dst, limitedReader)
	if err != nil {
		// Clean up the partially written file
		os.Remove(destPath)
		return fmt.Errorf("failed to write file: %w", err)
	}

	if written > maxUploadSize {
		os.Remove(destPath)
		return fmt.Errorf("file exceeds maximum size of %d bytes", maxUploadSize)
	}

	return nil
}